#!/usr/bin/env node
// Bundle migrations/*.sql into worker/_migrations_bundle.js so the Worker can
// run them at runtime without needing wrangler d1 migrations apply (which
// won't run on win32/arm64).
//
// Also writes worker/_version.js with the current git SHA + build time so
// /api/_version can report which commit is actually live (helpful when
// debugging "is my fix deployed?").

const fs = require('fs');
const path = require('path');
const { execSync } = require('child_process');

const MIGRATIONS_DIR = path.join(__dirname, '..', 'migrations');
const OUTPUT = path.join(__dirname, '..', 'worker', '_migrations_bundle.js');
const VERSION_OUTPUT = path.join(__dirname, '..', 'worker', '_version.js');

let gitSha = 'unknown';
try {
  gitSha = execSync('git rev-parse HEAD', { cwd: path.join(__dirname, '..') })
    .toString().trim();
} catch {
  // Best-effort: CI workspaces sometimes lack .git
}
const builtAt = new Date().toISOString();
fs.writeFileSync(
  VERSION_OUTPUT,
  `// AUTO-GENERATED by scripts/bundle-migrations.js. Do not edit by hand.\n` +
  `export const GIT_SHA = ${JSON.stringify(gitSha)};\n` +
  `export const BUILT_AT = ${JSON.stringify(builtAt)};\n`,
);
console.log(`Wrote ${VERSION_OUTPUT} (sha=${gitSha.slice(0, 8)})`);

const files = fs.readdirSync(MIGRATIONS_DIR)
  .filter(f => f.endsWith('.sql'))
  .sort();

const entries = files.map(f => {
  const sql = fs.readFileSync(path.join(MIGRATIONS_DIR, f), 'utf8');
  return { name: f, sql };
});

const body = [
  '// AUTO-GENERATED by scripts/bundle-migrations.js. Do not edit by hand.',
  'export const MIGRATIONS = [',
  ...entries.map(e => {
    const escaped = e.sql.replace(/\\/g, '\\\\').replace(/`/g, '\\`').replace(/\$\{/g, '\\${');
    return `  { name: ${JSON.stringify(e.name)}, sql: \`${escaped}\` },`;
  }),
  '];',
  '',
].join('\n');

fs.writeFileSync(OUTPUT, body);
console.log(`Wrote ${OUTPUT} (${entries.length} migrations)`);
